import request from '@/utils/request'

export const user = {
  getProfile: () => {
    return request({
      url: '/v1/users/profile/',
      method: 'get'
    })
  },

  updateProfile: (data) => {
    return request({
      url: '/v1/users/profile/',
      method: 'patch',
      data
    })
  },

  updateAvatar: (data) => {
    return request({
      url: '/v1/users/profile/avatar/',
      method: 'post',
      data
    })
  }
}
